      /* <flatten type="Javascript"> */
function getQueryFilterString(f, s) {
  var q = '', a = s.split(',');
  for (var i = 0; i < a.length; i++) {
    var c = $func.trim(a[i]), o = f.getItem(c), v = (o ? f.getItemValue(c) : c);
    q += String.fromCharCode(253);
    if (o) {
      switch (o.field.Type) {
        case 'DateTime':
          q += (v == null ? '' : $func.formatDateOrder(v));
          break;
        case 'Boolean':
          q += (v ? '1' : '0');
          break;
        default:
          q += $func.replace(v, '\'', String.fromCharCode(252));
          break;
      }
    } else q += $func.replace(v, '\'', String.fromCharCode(252));
  }
  return q;
}
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  changeLookupReadonly(f, 'ma_dvcs');
  var a = ['tk'];
  if (!f._extensions) {
    f.setItemValue('ngay_bc', new Date());
    f.request('GetDefaultValue', 'SetDefaultValue', a);
  }
  else setReferenceValue(f, a);
}
function close$VoucherFilter$(f) {
  try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}
}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, x = f.getItemValue('mau_bc'), d1 = f.getItem('ngay_hd1').value, d2 = f.getItem('ngay_hd2').value, b = f.getItemValue('isbalance');
      g._alterTitle = [null, [['%s', f.getItemValue('tk'), true], ['%d1', d1, true], ['%d2', d2, true]]];
      g._hiddenFields = [
        {Fields: 'ps_no_nt, ps_co_nt, du_dk_nt, du_ck_nt, nc_dk, nc_ck', Value: (x == '10' || x == '30')},
        {Fields: 'nc_dk2, nc_ck2', Value: (x == '20' || x == '40')}
      ];
      g._hiddenForms = [
        {Form: [0, 1, 5, 6], Value: (b == 1)},
        {Form: [2, 3, 7, 8], Value: (b == 0)}
      ];
      g._queryFilterString = getQueryFilterString(f, 'ngay_ht1, ngay_ht2, ngay_hd1, ngay_hd2, tk, ma_dvcs, mau_bc');
      if (g._$k != null) g._$k = [];
      remove$GridReport$Filter(g);
      break;
    case 'SetDefaultValue':
      f.setItemControlBehavior('ten_tk%l', result[0].Value, null, true);
      if (result[0].Value == '') f.setItemValue('tk', '');
      break;
    default:
      break;
  }
}
function setReferenceValue(f, a) {
  for (var i = 0; i < a.length; i++) {
    var r = $func.findField(a[i], f._fields).ItemReference;
    f.setItemValue(r, $func.findMemvar(r, f._extensions).NewValue);
  }
}
